export default {
  async fetch(request) {
    if (request.method === 'OPTIONS') return new Response(null, {headers:{'Access-Control-Allow-Origin':'*'}});
    const url = new URL(request.url);
    const path = url.pathname.replace(/\/+$/, '');

    if (path === '/boutiques') return Response.json(BOUTIQUES, {headers:CORS});
    if (path === '/homepages') return Response.json(HOMEPAGES, {headers:CORS});

    // /homepages/:domain — single domain lookup
    if (path.startsWith('/homepages/')) {
      const domain = path.slice('/homepages/'.length);
      const d = HOMEPAGES[domain];
      if (!d) return Response.json({ok:false,error:'Not found'}, {status:404,headers:{'Access-Control-Allow-Origin':'*'}});
      return Response.json({ok:true,...d}, {headers:CORS});
    }

    return Response.json({
      ok:true, boutiques:BOUTIQUES.length, homepages:Object.keys(HOMEPAGES).length,
      generated: '2026-06-12T19:47:03Z'
    }, {headers:CORS});
  }
};
